    40→// Helper function to extract text from various file formats
    41→async function extractTextFromFile(buffer, mimetype) {
    42→  try {
    43→    // Handle PDF files
    44→    if (mimetype === 'application/pdf' || buffer.toString('utf-8', 0, 4) === '%PDF') {
    45→      const pdfData = await pdfParse(buffer);
    46→      return pdfData.text;
    47→    }
    48→
    49→    // Handle DOCX files (application/vnd.openxmlformats-officedocument.wordprocessingml.document)
    50→    if (mimetype === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' ||
    51→        buffer.toString('utf-8', 0, 2) === 'PK') {
    52→      const result = await mammoth.extractRawText({ buffer });
    53→      return result.value;
    54→    }
    55→
    56→    // Handle plain text files (fallback)
    57→    const text = buffer.toString('utf-8');
    58→    if (text.length > 0 && /[a-zA-Z]{3,}/.test(text.substring(0, 500))) {
    59→      return text;
    60→    }
    61→
    62→    throw new Error('Unsupported file format or unable to extract text');
    63→  } catch (error) {
    64→    console.error('Text extraction error:', error.message);
    65→    throw error;
    66→  }
    67→}
