   405→                i
   406→              ]);
   407→              applySummary.education++;
   408→            }
   409→          }
   410→
   411→          // 4. Apply skills (upsert — won't duplicate due to UNIQUE constraint)
   412→          if (parsedData.skills && Array.isArray(parsedData.skills)) {
   413→            for (const skill of parsedData.skills) {
