  1693→// Auto-fill endpoint — returns stored data for pre-populating application forms
  1694→router.get('/auto-fill/:jobId', authMiddleware, async (req, res) => {
  1695→  try {
  1696→    const jobId = req.params.jobId;
  1697→
  1698→    // Get profile data
  1699→    const profile = await pool.query(`
  1700→      SELECT cp.*, u.name, u.email FROM candidate_profiles cp
  1701→      RIGHT JOIN users u ON u.id = cp.user_id WHERE u.id = $1
  1702→    `, [req.user.id]);
  1703→
  1704→    // Get resume URL
  1705→    const resumeData = await pool.query('SELECT resume_url FROM candidate_profiles WHERE user_id = $1', [req.user.id]);
  1706→
  1707→    // Get screening questions for this job
  1708→    const job = await pool.query('SELECT screening_questions FROM jobs WHERE id = $1', [jobId]);
  1709→    const screeningQuestions = job.rows[0]?.screening_questions || [];
  1710→
  1711→    // Find past answers for similar questions
  1712→    const pastApps = await pool.query(`
  1713→      SELECT screening_answers, cover_letter FROM job_applications
  1714→      WHERE candidate_id = $1 AND screening_answers IS NOT NULL
  1715→      ORDER BY applied_at DESC LIMIT 10
  1716→    `, [req.user.id]);
  1717→
  1718→    // Build auto-fill map for screening questions
  1719→    const answerMap = {};
  1720→    for (const q of screeningQuestions) {
  1721→      // Search past answers by category or similar question text
  1722→      for (const app of pastApps.rows) {
  1723→        const answers = app.screening_answers || {};
  1724→        // Direct ID match
  1725→        if (answers[q.id]) {
  1726→          answerMap[q.id] = { value: answers[q.id], source: 'previous_application' };
  1727→          break;
  1728→        }
  1729→        // Category match
  1730→        for (const [key, val] of Object.entries(answers)) {
  1731→          if (q.category && key.includes(q.category)) {
  1732→            answerMap[q.id] = { value: val, source: 'similar_question' };
  1733→            break;
  1734→          }
  1735→        }
  1736→      }
  1737→
  1738→      // Fallback: match from profile data
  1739→      if (!answerMap[q.id] && q.category) {
  1740→        const p = profile.rows[0] || {};
  1741→        if (q.category === 'salary' && p.salary_min) {
  1742→          answerMap[q.id] = { value: `$${p.salary_min.toLocaleString()} - $${(p.salary_max || p.salary_min).toLocaleString()}`, source: 'profile' };
  1743→        } else if (q.category === 'availability' && p.availability) {
  1744→          answerMap[q.id] = { value: p.availability, source: 'profile' };
  1745→        } else if (q.category === 'relocation') {
  1746→          answerMap[q.id] = { value: p.remote_preference === 'remote' ? 'No' : 'Yes', source: 'profile' };
  1747→        } else if (q.category === 'experience') {
  1748→          const yrs = p.years_experience || 0;
  1749→          const bracket = yrs < 1 ? '0-1 years' : yrs < 3 ? '1-3 years' : yrs < 5 ? '3-5 years' : yrs < 10 ? '5-10 years' : '10+ years';
  1750→          answerMap[q.id] = { value: bracket, source: 'profile' };
  1751→        }
  1752→      }
  1753→    }
  1754→
  1755→    // Find the most recent cover letter
  1756→    const lastCoverLetter = pastApps.rows.find(a => a.cover_letter)?.cover_letter || '';
  1757→
  1758→    res.json({
  1759→      success: true,
  1760→      auto_fill: {
  1761→        resume_url: resumeData.rows[0]?.resume_url || null,
  1762→        cover_letter: lastCoverLetter,
  1763→        screening_answers: answerMap,
  1764→        profile: {
  1765→          name: profile.rows[0]?.name,
  1766→          email: profile.rows[0]?.email,
  1767→          phone: profile.rows[0]?.phone,
  1768→          location: profile.rows[0]?.location,
  1769→        }
  1770→      }
  1771→    });
  1772→  } catch (err) {
  1773→    console.error('Auto-fill error:', err);
  1774→    res.status(500).json({ error: 'Failed to get auto-fill data' });
  1775→  }
  1776→});
